fn merge_sort(arr: &mut [i32]) {
    let len = arr.len();
    if len <= 1 { return; }
    let mid = len / 2;
    merge_sort(&mut arr[..mid]);
    merge_sort(&mut arr[mid..]);
    let merged = merge(&arr[..mid], &arr[mid..]);
    arr.copy_from_slice(&merged);
}
